import{_ as t,o as s,c as n,ai as i}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Type System","description":"","frontmatter":{"title":"Type System","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/type-system.md","filePath":"reference-manual/formal-reference/type-system.md"}'),a={name:"reference-manual/formal-reference/type-system.md"};function d(o,e,l,r,c,p){return s(),n("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/type-system.md for this page in Markdown format</div><h1 id="type-system" tabindex="-1">Type System <a class="header-anchor" href="#type-system" aria-label="Permalink to “Type System”">​</a></h1><h2 id="literals" tabindex="-1">Literals <a class="header-anchor" href="#literals" aria-label="Permalink to “Literals”">​</a></h2><p><strong>Syntax:</strong> <code>width&#39;base_value</code></p><ul><li><strong>width</strong>: positive integer or <code>CONST</code> name</li><li><strong>base</strong>: <code>b</code>, <code>d</code>, or <code>h</code></li><li>Binary allows <code>0</code>, <code>1</code>, <code>x</code>, <code>z</code> (underscore <code>_</code> for readability)</li><li>Decimal/hex do not allow <code>x</code> or <code>z</code></li><li>Unsized literals are not permitted</li><li><code>CONFIG.NAME</code> and <code>CONST</code> identifiers are compile-time integers and are not literals</li></ul><p><strong>Intrinsic width rules:</strong></p><ul><li>Binary: count digits excluding underscores</li><li>Decimal/hex: minimum bits needed to represent the value (leading zeros do not increase intrinsic width; value 0 has intrinsic width 1)</li></ul><p><strong>Extension rules:</strong></p><ul><li>MSB <code>0</code> or <code>1</code>: zero-extend</li><li>MSB <code>x</code>: extend with <code>x</code></li><li>MSB <code>z</code>: extend with <code>z</code> (binary only)</li></ul><p>Overflow (intrinsic width &gt; declared width) is a compile error.</p><p><strong>Examples:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>8&#39;b1010_0001    // binary, 8 bits</span></span>
<span class="line"><span>16&#39;hFF00        // hex, 16 bits</span></span>
<span class="line"><span>12&#39;d4095        // decimal, 12 bits</span></span>
<span class="line"><span>4&#39;bx            // intrinsic 1, extends to 4&#39;bxxxx</span></span>
<span class="line"><span>8&#39;hF            // intrinsic 4, zero-extended to 8&#39;h0F</span></span></code></pre></div><p><strong>Extension table:</strong></p><table tabindex="0"><thead><tr><th>MSB</th><th>Extension</th><th>Example</th></tr></thead><tbody><tr><td><code>0</code></td><td>zero-extend</td><td><code>4&#39;b0010</code> → <code>8&#39;b0000_0010</code></td></tr><tr><td><code>1</code></td><td>zero-extend</td><td><code>4&#39;b1010</code> → <code>8&#39;b0000_1010</code></td></tr><tr><td><code>x</code></td><td>x-extend</td><td><code>4&#39;bx</code> → <code>8&#39;bxxxx_xxxx</code></td></tr><tr><td><code>z</code></td><td>z-extend</td><td><code>4&#39;bz</code> → <code>8&#39;bzzzz_zzzz</code></td></tr></tbody></table><p><strong>Error conditions:</strong></p><ul><li>Unsized literals (<code>&#39;hFF</code>) → error</li><li>Decimal with <code>x</code>/<code>z</code> (<code>8&#39;d10x</code>) → error</li><li>Hex with <code>x</code>/<code>z</code> (<code>8&#39;hFx</code>, <code>8&#39;hz0</code>) → error</li><li>Undefined CONST in width → error</li><li>Overflow (intrinsic width &gt; declared width) → error</li></ul><h2 id="signedness-model" tabindex="-1">Signedness model <a class="header-anchor" href="#signedness-model" aria-label="Permalink to “Signedness model”">​</a></h2><p>All signals, literals, and operators in JZ-HDL are <strong>unsigned by default</strong>. There is no implicit signed type. For signed arithmetic, use the explicit signed intrinsic operators <code>sadd</code> and <code>smul</code>.</p><h2 id="bit-width-constraints" tabindex="-1">Bit-width constraints <a class="header-anchor" href="#bit-width-constraints" aria-label="Permalink to “Bit-width constraints”">​</a></h2><ul><li>Binary operators generally require identical operand widths.</li><li>Some operators have specialized width rules (see Expressions and Operators).</li><li>When widths differ, use explicit extension modifiers (<code>=z</code>, <code>=s</code>, <code>&lt;=z</code>, <code>&lt;=s</code>, <code>=&gt;z</code>, <code>=&gt;s</code>).</li><li>Truncation is never implicit; RHS wider than LHS is a compile error.</li></ul><h2 id="x-and-z-semantics" tabindex="-1">x and z semantics <a class="header-anchor" href="#x-and-z-semantics" aria-label="Permalink to “x and z semantics”">​</a></h2><ul><li><code>x</code>: intentional don&#39;t-care. Allowed only in binary literals. <ul><li>Expressions containing <code>x</code> bits are x-dependent.</li><li>X-dependent values must be provably masked before reaching any observable sink.</li></ul></li><li><code>z</code>: high-impedance (tri-state). Allowed only in binary literals. <ul><li>Nets read must have at least one active (0/1) driver per bit.</li></ul></li></ul><p><strong>Allowed uses of <code>x</code>:</strong></p><ul><li><code>x</code> in CASE/SELECT patterns (don&#39;t-care matching); <code>x</code> bits do not propagate.</li><li><code>x</code> in internal combinational values when structurally masked before observable sinks.</li></ul><p><strong>Forbidden uses:</strong></p><ul><li>Register reset literals must not contain <code>x</code> or <code>z</code>.</li><li>MEM initialization must not contain <code>x</code> or <code>z</code>.</li><li><code>x</code>/<code>z</code> digits in <code>h</code> or <code>d</code> literals are compile errors.</li></ul><h2 id="special-semantic-drivers" tabindex="-1">Special semantic drivers <a class="header-anchor" href="#special-semantic-drivers" aria-label="Permalink to “Special semantic drivers”">​</a></h2><p>Two reserved semantic drivers provide width-agnostic constants:</p><ul><li><code>GND</code>: Logic 0 — expands to match the target bit-width.</li><li><code>VCC</code>: Logic 1 — expands to match the target bit-width.</li></ul><p><strong>Rules:</strong></p><ul><li>GND/VCC are valid only as standalone assignment tokens (not in expressions, concatenations, slices, or indices).</li><li>GND/VCC are permitted as register reset values.</li><li>GND/VCC participate fully in the Exclusive Assignment Rule.</li></ul><p><strong>GND/VCC examples:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Register reset:</span></span>
<span class="line"><span>REGISTER { counter [16] = GND; }    // resets to 16&#39;h0000</span></span>
<span class="line"><span>REGISTER { flags   [8]  = VCC; }    // resets to 8&#39;hFF</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Wire tie-off:</span></span>
<span class="line"><span>ASYNCHRONOUS { unused_out &lt;= GND; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Port tie-off:</span></span>
<span class="line"><span>@new inst module {</span></span>
<span class="line"><span>  IN [8] data = GND;   // tie input low</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Illegal:</span></span>
<span class="line"><span>// result &lt;= GND + 1;</span><span>    // ERROR: GND not allowed in expressions</span></span>
<span class="line"><span>// {a, GND} &lt;= expr;</span><span>     // ERROR: GND not allowed in concatenation</span></span>
<span class="line"><span>// data[0] &lt;= GND;</span><span>       // ERROR: GND not allowed in slices</span></span>
<span class="line"><span>// IF (GND) { ... }</span><span>      // ERROR: GND not allowed as condition</span></span></code></pre></div><h2 id="constants-hierarchy" tabindex="-1">Constants hierarchy <a class="header-anchor" href="#constants-hierarchy" aria-label="Permalink to “Constants hierarchy”">​</a></h2><table tabindex="0"><thead><tr><th>Kind</th><th>Scope</th><th>Sized?</th><th>Usable at runtime?</th><th>Reference syntax</th></tr></thead><tbody><tr><td><code>CONST</code></td><td>Module-local</td><td>No (integer)</td><td>No</td><td>bare name</td></tr><tr><td><code>CONFIG</code></td><td>Project-wide</td><td>No (integer)</td><td>No</td><td><code>CONFIG.NAME</code></td></tr><tr><td><code>@global</code></td><td>All modules</td><td>Yes (sized literal)</td><td>Yes</td><td><code>global_name.CONST_ID</code></td></tr></tbody></table><ul><li>CONST/CONFIG are compile-time integers for widths, depths, and OVERRIDE.</li><li>@global entries are sized literals usable in signal expressions.</li><li>To use a constant value at runtime, use <code>@global</code> or <code>lit(width, value)</code>.</li></ul>`,36)])])}const m=t(a,[["render",d]]);export{u as __pageData,m as default};
